const seasons = [
  "2024-25",
  "2023-24",
  "2022-23",
  "2021-22"
];

return seasons.map(season => ({
  json: { season }
}));

function slugify(text) {
  return String(text || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

function pad2(n) {
  return String(n).padStart(2, "0");
}

function parseSeason(text, itemJson) {
  let seasonRaw =
    itemJson.season ||
    itemJson.input?.season ||
    itemJson.params?.season ||
    null;

  if (!seasonRaw) {
    const seasonMatch = String(text).match(/\b(20\d{2})\/(\d{2})\b/);
    if (seasonMatch) {
      seasonRaw = `${seasonMatch[1]}-${seasonMatch[2]}`;
    }
  }

  const season = seasonRaw ? seasonRaw.replace("-", "/") : null;
  return { seasonRaw, season };
}

function monthToNumber(mon) {
  const months = {
    Jan: 1, Feb: 2, Mar: 3, Apr: 4, May: 5, Jun: 6,
    Jul: 7, Aug: 8, Sep: 9, Oct: 10, Nov: 11, Dec: 12,
  };
  return months[mon] || null;
}

function buildMatchDate(season, monStr, dayStr, explicitYear = null) {
  const month = monthToNumber(monStr);
  const day = Number(dayStr);
  if (!month || !day) return null;

  let year = null;
  if (explicitYear) {
    year = Number(explicitYear);
  } else {
    if (!season) return null;
    const seasonMatch = season.match(/^(\d{4})\/(\d{2})$/);
    if (!seasonMatch) return null;
    const startYear = Number(seasonMatch[1]);
    const endYear = Number(`20${seasonMatch[2]}`);
    year = month >= 7 ? startYear : endYear;
  }

  return `${year}-${pad2(month)}-${pad2(day)}`;
}

function normalizeKickoffTime(kickoffText) {
  if (!kickoffText) return null;
  return kickoffText.replace(".", ":") + ":00";
}

// Extrae fecha de una línea. Formatos soportados:
// [Thu Aug/15 2024]  [Fri Aug/16]  Thu Aug/15 2024  Fri Aug/16
// Mon Aug/19  Sat Aug/17  etc.
function extractDateFromLine(line, season) {
  if (!line) return null;

  let s = String(line).trim();

  // Quitar corchetes tipo [Thu Aug/15 2024] o [Fri Aug/16]
  s = s.replace(/^\[/, "").replace(/\]$/, "").trim();
  // Quitar prefijo "# Date" o "#"
  s = s.replace(/^#\s*Date\s*/i, "").replace(/^#\s*/, "").trim();
  // Quitar sufijo tipo " - something"
  if (s.includes(" - ")) s = s.split(" - ")[0].trim();
  // Quitar sufijo entre paréntesis
  s = s.replace(/\s+\([^)]*\)\s*$/, "").trim();

  const WEEKDAYS = "Mon|Tue|Wed|Thu|Fri|Sat|Sun";
  const MON = "[A-Z][a-z]{2}";
  const DAY = "\\d{1,2}";
  const YEAR = "20\\d{2}";

  // Con día semana + año: "Thu Aug/15 2024"
  let m = s.match(new RegExp(`^(?:${WEEKDAYS})\\s+(${MON})\\/(${DAY})\\s+(${YEAR})$`));
  if (m) return buildMatchDate(season, m[1], m[2], m[3]);

  // Con día semana, sin año: "Fri Aug/16"
  m = s.match(new RegExp(`^(?:${WEEKDAYS})\\s+(${MON})\\/(${DAY})$`));
  if (m) return buildMatchDate(season, m[1], m[2], null);

  // Sin día semana + año: "Aug/15 2024"
  m = s.match(new RegExp(`^(${MON})\\/(${DAY})\\s+(${YEAR})$`));
  if (m) return buildMatchDate(season, m[1], m[2], m[3]);

  // Solo mes/dia: "Aug/15"
  m = s.match(new RegExp(`^(${MON})\\/(${DAY})$`));
  if (m) return buildMatchDate(season, m[1], m[2], null);

  return null;
}

function isDateLine(line) {
  if (!line) return false;
  const s = String(line).trim();
  // Línea que es SOLO una fecha (con o sin corchetes, con o sin weekday)
  if (/^(?:#\s*)?Date$/i.test(s)) return true;
  return extractDateFromLine(s, "2000/01") !== null;
}

function isJunkLine(line) {
  if (!line) return true;
  const s = String(line).trim();
  return (
    s.startsWith("=") ||
    /^spain primera division/i.test(s) ||
    /^primera divisi[oó]n/i.test(s) ||
    /^matches\s+\d+/i.test(s) ||
    /^teams\s+\d+/i.test(s) ||
    /^#\s*Date\s+\w+/i.test(s) ||   // "# Date Thu Aug/15..."  — es fecha, no junk
    /^#\s*Teams/i.test(s) ||
    /^#\s*Matches/i.test(s)
  );
}

const output = [];

for (const item of items) {
  const raw = item.json.data || item.json.body || "";
  let text = String(raw);

  // Normalizar saltos de línea
  text = text
    .replace(/\\r\\n/g, "\n")
    .replace(/\\n/g, "\n")
    .replace(/\\r/g, "\n")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n");

  // Inyectar separadores para asegurar que matchdays y fechas queden en líneas propias
  text = text
    .replace(/((?:»\s*)?Matchday\s+\d+)/gi, "\n$1\n")
    .replace(/(#\s*Date)/gi, "\n$1\n")
    // Fechas con corchetes tipo [Thu Aug/15 2024] o [Fri Aug/16]
    .replace(/(\[(?:Mon|Tue|Wed|Thu|Fri|Sat|Sun)\s+[A-Z][a-z]{2}\/\d{1,2}(?:\s+20\d{2})?\])/g, "\n$1\n")
    // Fechas sin corchetes al inicio de línea (precedidas de newline o inicio)
    .replace(/((?:^|\n)\s*(?:Mon|Tue|Wed|Thu|Fri|Sat|Sun)\s+[A-Z][a-z]{2}\/\d{1,2}(?:\s+20\d{2})?(?:\s*$|\s+(?!\d{2}\.\d{2}|\d+-\d+)))/gm, "\n$1\n");

  const { seasonRaw, season } = parseSeason(text, item.json);

  const lines = text
    .split(/\n+/)
    .map(l => l.trim())
    .filter(Boolean);

  let currentBlockDate = null;
  let currentMatchday = null;

  for (const rawLine of lines) {
    const line = rawLine.trim();
    if (!line) continue;

    // ---- Detectar Matchday ----
    const mdMatch = line.match(/(?:»\s*)?Matchday\s+(\d+)/i);
    if (mdMatch) {
      currentMatchday = Number(mdMatch[1]);
      continue;
    }

    // ---- Detectar línea de fecha pura ----
    const detectedDate = extractDateFromLine(line, season);
    if (detectedDate) {
      currentBlockDate = detectedDate;
      continue; // Esta línea ES una fecha, no un partido
    }

    // ---- Saltar basura ----
    if (isJunkLine(line)) continue;

    // ---- Intentar extraer partido ----
    // Primero limpiar prefijos de fecha inline que puedan estar pegados
    // (ej: "Thu Aug/15 2024\n  19.00 Athletic Club v Getafe CF 1-1")
    // En este punto ya deberían estar separados por el split, pero por si acaso:
    let matchLine = line
      .replace(/^(?:Mon|Tue|Wed|Thu|Fri|Sat|Sun)\s+[A-Z][a-z]{2}\/\d{1,2}(?:\s+20\d{2})?\s+/i, "")
      .replace(/^[A-Z][a-z]{2}\/\d{1,2}(?:\s+20\d{2})?\s+/i, "")
      .trim();

    if (!matchLine) continue;

    let kickoffText = null;
    let homeTeam = null;
    let awayTeam = null;
    let homeScore = null;
    let awayScore = null;
    let htHomeScore = null;
    let htAwayScore = null;
    let status = "scheduled";
    let m = null;

    // Formato 1: "19.00  Athletic Club  v  Getafe CF  1-1 (1-0)"
    m = matchLine.match(
      /^(?:(\d{1,2}\.\d{2})\s+)?(.+?)\s+v\s+(.+?)\s+(\d+)-(\d+)(?:\s+\((\d+)-(\d+)\))?$/i
    );
    if (m) {
      kickoffText = m[1] || null;
      homeTeam = m[2].trim();
      awayTeam = m[3].trim();
      homeScore = Number(m[4]);
      awayScore = Number(m[5]);
      htHomeScore = m[6] != null ? Number(m[6]) : null;
      htAwayScore = m[7] != null ? Number(m[7]) : null;
      status = "finished";
    }

    // Formato 2: "19.00  Athletic Club  v  Getafe CF" (sin resultado)
    if (!homeTeam) {
      m = matchLine.match(/^(?:(\d{1,2}\.\d{2})\s+)?(.+?)\s+v\s+(.+)$/i);
      if (m) {
        kickoffText = m[1] || null;
        homeTeam = m[2].trim();
        awayTeam = m[3].trim();
        status = "scheduled";
      }
    }

    // Formato 3 (openfootball legacy): "Athletic Club  1-1 (1-0)  Getafe CF"
    if (!homeTeam) {
      m = matchLine.match(
        /^(?:(\d{1,2}\.\d{2})\s+)?(.+?)\s+(\d+)-(\d+)(?:\s+\((\d+)-(\d+)\))?\s+(.+)$/i
      );
      if (m) {
        kickoffText = m[1] || null;
        homeTeam = m[2].trim();
        homeScore = Number(m[3]);
        awayScore = Number(m[4]);
        htHomeScore = m[5] != null ? Number(m[5]) : null;
        htAwayScore = m[6] != null ? Number(m[6]) : null;
        awayTeam = m[7].trim();
        status = "finished";
      }
    }

    if (!homeTeam || !awayTeam) continue;

    const kickoffTime = normalizeKickoffTime(kickoffText);
    const kickoffAtLocal =
      currentBlockDate && kickoffTime
        ? `${currentBlockDate}T${kickoffTime}`
        : null;

    output.push({
      json: {
        season,
        matchday: currentMatchday,
        match_date: currentBlockDate,
        kickoff_text: kickoffText,
        kickoff_time: kickoffTime,
        kickoff_at_local: kickoffAtLocal,
        utc_date: null,

        home_team_name: homeTeam,
        away_team_name: awayTeam,
        home_team_slug_guess: slugify(homeTeam),
        away_team_slug_guess: slugify(awayTeam),

        home_score: homeScore,
        away_score: awayScore,
        home_ht_score: htHomeScore,
        away_ht_score: htAwayScore,

        status,
        source: "openfootball",
        source_id: [
          "openfootball",
          seasonRaw || "noseason",
          currentMatchday || "nomd",
          slugify(homeTeam),
          slugify(awayTeam),
          currentBlockDate || "nodate",
          kickoffText || "notime"
        ].join("-")
      }
    });
  }
}

return output;

function slugify(text) {
  return String(text || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

const aliasMap = {
  "atletico-madrid": "club-atletico-de-madrid",
  "club-atletico-de-madrid": "club-atletico-de-madrid",

  "athletic-bilbao": "athletic-club",
  "athletic": "athletic-club",

  "espanyol": "rcd-espanyol-de-barcelona",
  "espanyol-de-barcelona": "rcd-espanyol-de-barcelona",
  "rcd-espanyol": "rcd-espanyol-de-barcelona",

  "alaves": "deportivo-alaves",
  "deportivo-alaves": "deportivo-alaves",

  "real-sociedad": "real-sociedad-de-futbol",
  "real-sociedad-de-san-sebastian": "real-sociedad-de-futbol",

  "betis": "real-betis-balompie",
  "real-betis": "real-betis-balompie",
  "real-betis-balompie": "real-betis-balompie",

  "mallorca": "rcd-mallorca",
  "real-mallorca": "rcd-mallorca",

  "celta": "rc-celta-de-vigo",
  "celta-vigo": "rc-celta-de-vigo",
  "real-club-celta-de-vigo": "rc-celta-de-vigo",

  "leganes": "cd-leganes",
  "deportivo-leganes": "cd-leganes",

  "deportivo-la-coruna": "rc-deportivo-de-la-coruna",
  "deportivo": "rc-deportivo-de-la-coruna",
  "rc-deportivo": "rc-deportivo-de-la-coruna",
  "la-coruna": "rc-deportivo-de-la-coruna",

  "barcelona": "fc-barcelona",
  "fc-barcelona": "fc-barcelona",

  "sevilla": "sevilla-fc",
  "sevilla-fc": "sevilla-fc",

  "valencia": "valencia-cf",
  "valencia-cf": "valencia-cf",

  "villarreal": "villarreal-cf",
  "villarreal-cf": "villarreal-cf",

  "getafe": "getafe-cf",
  "getafe-cf": "getafe-cf",

  "osasuna": "ca-osasuna",
  "ca-osasuna": "ca-osasuna",

  "girona": "girona-fc",
  "girona-fc": "girona-fc",

  "rayo": "rayo-vallecano-de-madrid",
  "rayo-vallecano": "rayo-vallecano-de-madrid",
  "rayo-vallecano-de-madrid": "rayo-vallecano-de-madrid",

  "real-madrid": "real-madrid-cf",
  "real-madrid-cf": "real-madrid-cf",

  "las-palmas": "ud-las-palmas",
  "ud-las-palmas": "ud-las-palmas",

  "real-valladolid": "real-valladolid-cf",
  "real-valladolid-cf": "real-valladolid-cf",

  "oviedo": "real-oviedo",
  "real-oviedo": "real-oviedo",

  "elche": "elche-cf",
  "elche-cf": "elche-cf",

  "levante": "levante-ud",
  "levante-ud": "levante-ud"
};

const merged = items.map(i => i.json);

const teamsContainer = merged.find(i => Array.isArray(i.teams));
const teams = teamsContainer?.teams || [];
const matches = merged.filter(i => !Array.isArray(i.teams));

const teamsBySlug = new Map();
const teamsByNameSlug = new Map();

for (const team of teams) {
  const slug = slugify(team.slug || "");
  const nameSlug = slugify(team.name || "");

  if (slug) teamsBySlug.set(slug, team);
  if (nameSlug) teamsByNameSlug.set(nameSlug, team);
}

function resolveTeam(rawSlugGuess, rawName) {
  let guess = slugify(rawSlugGuess || rawName || "");

  guess = aliasMap[guess] || guess;

  return (
    teamsBySlug.get(guess) ||
    teamsByNameSlug.get(guess) ||
    teamsBySlug.get(aliasMap[slugify(rawName || "")] || "") ||
    teamsByNameSlug.get(slugify(rawName || "")) ||
    null
  );
}

return matches.map(match => {
  const homeTeam = resolveTeam(match.home_team_slug_guess, match.home_team_name);
  const awayTeam = resolveTeam(match.away_team_slug_guess, match.away_team_name);

  return {
    json: {
      ...match,
      competition_id: "a6d5fa20-1a02-4aa8-bd08-707a87c488d6",
      home_team_id: homeTeam ? homeTeam.id : null,
      away_team_id: awayTeam ? awayTeam.id : null
    }
  };
});

const chunkSize = 50;
const rows = items.map(i => i.json);

const cleaned = rows.map(r => ({
  competition_id: r.competition_id,
  season: r.season,
  matchday: r.matchday ?? null,
  home_team_id: r.home_team_id,
  away_team_id: r.away_team_id,
  stadium_id: null,
  kickoff_at: r.kickoff_at_local ?? null,
  home_score: r.home_score ?? null,
  away_score: r.away_score ?? null,
  status: r.status,
  source: "openfootball",
  source_id: r.source_id
}));

const batches = [];
for (let i = 0; i < cleaned.length; i += chunkSize) {
  batches.push({
    json: {
      batch: cleaned.slice(i, i + chunkSize)
    }
  });
}

return batches;

const out = [];

for (const item of items) {
  const j = item.json;

  if (!j.home_team_id && j.home_team_name) {
    out.push({
      json: {
        name: j.home_team_name,
        slug: j.home_team_slug_guess || null,
        external_id: null,
        source: "openfootball",
        source_id: j.home_team_slug_guess || null
      }
    });
  }

  if (!j.away_team_id && j.away_team_name) {
    out.push({
      json: {
        name: j.away_team_name,
        slug: j.away_team_slug_guess || null,
        external_id: null,
        source: "openfootball",
        source_id: j.away_team_slug_guess || null
      }
    });
  }
}

return out;

const seen = new Set();
const unique = [];

for (const item of items) {
  const key = (item.json.slug || item.json.name || "").toLowerCase().trim();
  if (!key) continue;

  if (!seen.has(key)) {
    seen.add(key);
    unique.push({
      json: item.json
    });
  }
}

return unique;

return [
  {
    json: {
      payload: items.map(i => ({
        name: i.json.name,
        slug: i.json.slug,
        country_id: "37f46503-683b-4aa0-be0b-dea6d5db4b50",
        source: "openfootball",
        source_id: i.json.source_id ?? null,
        external_id: null
      }))
    }
  }
];
